import React, { useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { createPost } from '../redux/thunks/postThunks';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import './CreatePost.css';

const CreatePost = () => {
  const { user } = useSelector((state) => state.auth);
  const { loading } = useSelector((state) => state.posts);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [description, setDescription] = useState('');
  const [visibility, setVisibility] = useState('Public');
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [videoFile, setVideoFile] = useState(null);
  const [videoPreview, setVideoPreview] = useState(null);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const avatarUrl = getImageUrl(user?.imageURL?.thumbnail || user?.imageURL);

  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImageFile(file);
    setVideoFile(null);
    setVideoPreview(null);
    const reader = new FileReader();
    reader.onload = () => setImagePreview(reader.result);
    reader.readAsDataURL(file);
  };

  const handleVideoSelect = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setVideoFile(file);
    setImageFile(null);
    setImagePreview(null);
    setVideoPreview(URL.createObjectURL(file));
  };

  const handleRemoveMedia = () => {
    setImageFile(null);
    setImagePreview(null);
    setVideoFile(null);
    setVideoPreview(null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!description.trim()) {
      toast.warn('Please write something');
      return;
    }

    const formData = new FormData();
    formData.append('description', description.trim());
    formData.append('postType', visibility);
    if (imageFile) formData.append('image', imageFile);
    if (videoFile) formData.append('video', videoFile);

    const result = await dispatch(createPost(formData));
    if (!result.error) {
      toast.success('Post created!');
      navigate('/');
    } else {
      toast.error(result.payload || 'Failed to create post');
    }
  };

  return (
    <div className="create-post-page">
      <div className="create-post-header">
        <button className="create-back-btn" onClick={() => navigate(-1)}>←</button>
        <h1 className="create-title">Create Post</h1>
        <div className="create-header-spacer" />
      </div>

      <form className="create-form" onSubmit={handleSubmit}>
        <div className="create-author-row">
          {avatarUrl ? (
            <img src={avatarUrl} alt="" className="create-avatar" />
          ) : (
            <div className="create-avatar-placeholder">
              {(user?.firstName || 'U')[0].toUpperCase()}
            </div>
          )}
          <div>
            <span className="create-author-name">{user?.firstName} {user?.lastName}</span>
            <select
              className="create-visibility"
              value={visibility}
              onChange={(e) => setVisibility(e.target.value)}
            >
              <option value="Public">Public</option>
              <option value="Friend_Only">Friends Only</option>
            </select>
          </div>
        </div>

        <textarea
          className="create-textarea"
          placeholder="What's on your mind?"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          rows={5}
        />

        {/* Media preview */}
        {(imagePreview || videoPreview) && (
          <div className="create-media-preview">
            {imagePreview && <img src={imagePreview} alt="Preview" className="create-preview-img" />}
            {videoPreview && <video src={videoPreview} className="create-preview-video" controls />}
            <button type="button" className="create-remove-media" onClick={handleRemoveMedia}>✕</button>
          </div>
        )}

        {/* Media buttons */}
        <div className="create-media-btns">
          <label className="create-media-btn">
            📷 Photo
            <input type="file" accept="image/*" onChange={handleImageSelect} hidden />
          </label>
          <label className="create-media-btn">
            🎥 Video
            <input type="file" accept="video/*" onChange={handleVideoSelect} hidden />
          </label>
        </div>

        <button
          type="submit"
          className="create-submit-btn"
          disabled={loading || !description.trim()}
        >
          {loading ? 'Sharing...' : 'Share Post'}
        </button>
      </form>
    </div>
  );
};

export default CreatePost;
